import{_ as s,j as a,p as o,at as i}from"./chunks/framework.CFWbLlrS.js";const p=JSON.parse('{"title":"会话 (Session)","description":"","frontmatter":{},"headers":[],"relativePath":"zh-CN/sdk/session.md","filePath":"zh-CN/sdk/session.md"}'),n={name:"zh-CN/sdk/session.md"};function l(d,e,r,t,c,h){return a(),o("div",null,[...e[0]||(e[0]=[i('<div style="display:none;" hidden="true" aria-hidden="true">Are you an LLM? You can read better optimized documentation at /sdk/session.md for this page in Markdown format</div><h1 id="会话" tabindex="-1">会话 (Session) <a class="header-anchor" href="#会话" aria-label="Permalink to “会话 (Session)”">​</a></h1><p><strong>会话 (Session)</strong> 是对事件的封装，包含了事件的所有信息以及触发事件的 Bot 实例。事件监听器的回调函数将会收到一个 Session 实例作为参数。</p><h2 id="构造函数" tabindex="-1">构造函数 <a class="header-anchor" href="#构造函数" aria-label="Permalink to “构造函数”">​</a></h2><h3 id="new-session" tabindex="-1">new Session(bot, event) <a class="header-anchor" href="#new-session" aria-label="Permalink to “new Session(bot, event)”">​</a></h3><ul><li><strong>bot:</strong> <a href="./bot.html"><code>Bot</code></a> 机器人实例</li><li><strong>event:</strong> <code>Partial&lt;Event&gt;</code> 事件数据</li></ul><p>创建一个新的会话实例。<code>selfId</code>, <code>platform</code> 和 <code>timestamp</code> 会自动从 Bot 中填充默认值。</p><div class="tip custom-block"><p class="custom-block-title custom-block-title-default">TIP</p><p>通常不需要手动构造 Session，而是通过 <a href="./bot.html#bot-session-event"><code>bot.session()</code></a> 创建。</p></div><h2 id="实例属性" tabindex="-1">实例属性 <a class="header-anchor" href="#实例属性" aria-label="Permalink to “实例属性”">​</a></h2><h3 id="session-sn" tabindex="-1">session.sn <a class="header-anchor" href="#session-sn" aria-label="Permalink to “session.sn”">​</a></h3><ul><li>类型: <code>number</code></li></ul><p>会话的序列号，在当前上下文中唯一。</p><h3 id="session-bot" tabindex="-1">session.bot <a class="header-anchor" href="#session-bot" aria-label="Permalink to “session.bot”">​</a></h3><ul><li>类型: <a href="./bot.html"><code>Bot</code></a></li></ul><p>触发事件的 Bot 实例。</p><h3 id="session-event" tabindex="-1">session.event <a class="header-anchor" href="#session-event" aria-label="Permalink to “session.event”">​</a></h3><ul><li>类型: <code>Event</code></li></ul><p>原始的事件对象，包含事件的全部信息。</p><h3 id="session-locales" tabindex="-1">session.locales <a class="header-anchor" href="#session-locales" aria-label="Permalink to “session.locales”">​</a></h3><ul><li>类型: <code>string[]</code></li></ul><p>当前会话的语言偏好列表。</p><h2 id="事件访问器" tabindex="-1">事件访问器 <a class="header-anchor" href="#事件访问器" aria-label="Permalink to “事件访问器”">​</a></h2><p>以下属性是对 <code>session.event</code> 中字段的快捷访问，可读可写。</p><h3 id="session-type" tabindex="-1">session.type <a class="header-anchor" href="#session-type" aria-label="Permalink to “session.type”">​</a></h3><ul><li>类型: <code>string</code></li></ul><p>事件类型，派生自 <code>event.type</code>。</p><h3 id="session-selfid" tabindex="-1">session.selfId <a class="header-anchor" href="#session-selfid" aria-label="Permalink to “session.selfId”">​</a></h3><ul><li>类型: <code>string</code></li></ul><p>机器人的平台账号，派生自 <code>event.selfId</code>。</p><h3 id="session-platform" tabindex="-1">session.platform <a class="header-anchor" href="#session-platform" aria-label="Permalink to “session.platform”">​</a></h3><ul><li>类型: <code>string</code></li></ul><p>事件所属的平台名称，派生自 <code>event.platform</code>。</p><h3 id="session-timestamp" tabindex="-1">session.timestamp <a class="header-anchor" href="#session-timestamp" aria-label="Permalink to “session.timestamp”">​</a></h3><ul><li>类型: <code>number</code></li></ul><p>事件的时间戳，派生自 <code>event.timestamp</code>。</p><h3 id="session-userid" tabindex="-1">session.userId <a class="header-anchor" href="#session-userid" aria-label="Permalink to “session.userId”">​</a></h3><ul><li>类型: <code>string</code></li></ul><p>触发事件的用户 ID，派生自 <code>event.user.id</code>。</p><h3 id="session-channelid" tabindex="-1">session.channelId <a class="header-anchor" href="#session-channelid" aria-label="Permalink to “session.channelId”">​</a></h3><ul><li>类型: <code>string</code></li></ul><p>事件所在的频道 ID，派生自 <code>event.channel.id</code>。</p><h3 id="session-channelname" tabindex="-1">session.channelName <a class="header-anchor" href="#session-channelname" aria-label="Permalink to “session.channelName”">​</a></h3><ul><li>类型: <code>string</code></li></ul><p>事件所在的频道名称，派生自 <code>event.channel.name</code>。</p><h3 id="session-guildid" tabindex="-1">session.guildId <a class="header-anchor" href="#session-guildid" aria-label="Permalink to “session.guildId”">​</a></h3><ul><li>类型: <code>string</code></li></ul><p>事件所在的群组 ID，派生自 <code>event.guild.id</code>。</p><h3 id="session-guildname" tabindex="-1">session.guildName <a class="header-anchor" href="#session-guildname" aria-label="Permalink to “session.guildName”">​</a></h3><ul><li>类型: <code>string</code></li></ul><p>事件所在的群组名称，派生自 <code>event.guild.name</code>。</p><h3 id="session-messageid" tabindex="-1">session.messageId <a class="header-anchor" href="#session-messageid" aria-label="Permalink to “session.messageId”">​</a></h3><ul><li>类型: <code>string</code></li></ul><p>事件关联的消息 ID，派生自 <code>event.message.id</code>。</p><h3 id="session-operatorid" tabindex="-1">session.operatorId <a class="header-anchor" href="#session-operatorid" aria-label="Permalink to “session.operatorId”">​</a></h3><ul><li>类型: <code>string</code></li></ul><p>事件的操作者 ID，派生自 <code>event.operator.id</code>。</p><h3 id="session-roleid" tabindex="-1">session.roleId <a class="header-anchor" href="#session-roleid" aria-label="Permalink to “session.roleId”">​</a></h3><ul><li>类型: <code>string</code></li></ul><p>事件关联的角色 ID，派生自 <code>event.role.id</code>。</p><h3 id="session-quote" tabindex="-1">session.quote <a class="header-anchor" href="#session-quote" aria-label="Permalink to “session.quote”">​</a></h3><ul><li>类型: <a href="./../resources/message.html#def-message"><code>Message</code></a></li></ul><p>引用的消息，派生自 <code>event.message.quote</code>。</p><h3 id="session-referrer" tabindex="-1">session.referrer <a class="header-anchor" href="#session-referrer" aria-label="Permalink to “session.referrer”">​</a></h3><ul><li>类型: <code>any</code></li></ul><p>平台上下文信息，用于被动请求场景。派生自 <code>event.referrer</code>。</p><h2 id="计算属性" tabindex="-1">计算属性 <a class="header-anchor" href="#计算属性" aria-label="Permalink to “计算属性”">​</a></h2><h3 id="session-isdirect" tabindex="-1">session.isDirect <a class="header-anchor" href="#session-isdirect" aria-label="Permalink to “session.isDirect”">​</a></h3><ul><li>类型: <code>boolean</code></li></ul><p>当前会话是否为私聊。当 <code>event.channel.type</code> 为 <code>DIRECT</code> 时返回 <code>true</code>。</p><h3 id="session-content" tabindex="-1">session.content <a class="header-anchor" href="#session-content" aria-label="Permalink to “session.content”">​</a></h3><ul><li>类型: <code>string</code></li></ul><p>消息内容的字符串形式。读取时将 <code>event.message.elements</code> 序列化为字符串；设置时将字符串解析为消息元素，并自动提取 <code>quote</code> 元素。</p><h3 id="session-elements" tabindex="-1">session.elements <a class="header-anchor" href="#session-elements" aria-label="Permalink to “session.elements”">​</a></h3><ul><li>类型: <code>Element[]</code></li></ul><p>消息的元素数组，派生自 <code>event.message.elements</code>。</p><h3 id="session-author" tabindex="-1">session.author <a class="header-anchor" href="#session-author" aria-label="Permalink to “session.author”">​</a></h3><h2 id="实例方法" tabindex="-1">实例方法 <a class="header-anchor" href="#实例方法" aria-label="Permalink to “实例方法”">​</a></h2><h3 id="session-setinternal" tabindex="-1">session.setInternal(type, data) <a class="header-anchor" href="#session-setinternal" aria-label="Permalink to “session.setInternal(type, data)”">​</a></h3><ul><li><strong>type:</strong> <code>string</code> 内部事件类型</li><li><strong>data:</strong> <code>any</code> 内部事件数据</li></ul><p>设置内部事件信息。将 <code>_type</code> 和 <code>_data</code> 写入事件对象，并将 <code>data</code> 挂载到 <code>session[type]</code> 上。</p><h3 id="session-transform" tabindex="-1">session.transform(elements) <a class="header-anchor" href="#session-transform" aria-label="Permalink to “session.transform(elements)”">​</a></h3><ul><li><strong>elements:</strong> <code>Element[]</code> 消息元素</li><li>返回值: <code>Promise&lt;Element[]&gt;</code></li></ul><p>对消息元素进行组件转换。递归地将自定义组件替换为其渲染结果。</p>',83)])])}const u=s(n,[["render",l]]);export{p as __pageData,u as default};
